        throw new NullPointerException("name cannot be null");
    }
    if (!name.matches("^McEliece-(6688128|6688128f|6688128pc|6688128pcf|6960119|6960119f|6960119pc|6960119pcf|8192128|8192128f|8192128pc|8192128pcf)$")) {
